unsigned int *__fastcall xtea_encrypt(unsigned int *a1, const unsigned int *a2)
{
    unsigned int *result; // rax
    int i; // [rsp+0h] [rbp-10h]
    unsigned int v4; // [rsp+4h] [rbp-Ch]
    unsigned int v5; // [rsp+8h] [rbp-8h]
    unsigned int v6; // [rsp+Ch] [rbp-4h]

    v6 = *a1;
    v5 = a1[1];
    v4 = 0;
    for ( i = 0; i <= 31; ++i )
    {
        v6 += (v5 + ((v5 >> 5) ^ (16 * v5))) ^ (a2[v4 & 3] + v4);
        v4 -= 1640531527;
        v5 += (v6 + ((v6 >> 5) ^ (16 * v6))) ^ (a2[(v4 >> 11) & 3] + v4);
    }
    *a1 = v6;
    result = a1 + 1;
    a1[1] = v5;
    return result;
}
