__int64 __fastcall rc4_crypt(__int64 a1, __int64 a2, int a3)
{
    __int64 result; // rax
    char v4; // [rsp+3h] [rbp-Dh]
    unsigned int i; // [rsp+4h] [rbp-Ch]
    int v6; // [rsp+8h] [rbp-8h]
    int v7; // [rsp+Ch] [rbp-4h]

    v7 = 0;
    v6 = 0;
    for ( i = 0; ; ++i )
    {
        result = i;
        if ( (int)i >= a3 )
            break;
        v7 = (v7 + 1) % 256;
        v6 = (v6 + *(unsigned __int8 *)(v7 + a1)) % 256;
        v4 = *(char *)(v7 + a1);
        *(char *)(v7 + a1) = *(char *)(v6 + a1);
        *(char *)(a1 + v6) = v4;
        *(char *)((int)i + a2) ^= *(char *)((unsigned __int8)(*(char *)(v7 + a1) + *(char *)(v6 + a1)) + a1);
    }
    return result;
}

unsigned __int64 __fastcall rc4_init(__int64 a1, __int64 a2, int a3)
{
    unsigned __int64 result; // rax
    unsigned __int8 v4; // [rsp+7h] [rbp-9h]
    int v5; // [rsp+8h] [rbp-8h]
    int i; // [rsp+Ch] [rbp-4h]
    int j; // [rsp+Ch] [rbp-4h]

    v5 = 0;
    for ( i = 0; i <= 255; ++i )
    {
        result = i + a1;
        *(char *)result = i;
    }
    for ( j = 0; j <= 255; ++j )
    {
        v5 = (*(unsigned __int8 *)(j + a1) + v5 + *(unsigned __int8 *)(j % a3 + a2)) % 256;
        v4 = *(char *)(j + a1);
        *(char *)(j + a1) = *(char *)(v5 + a1);
        result = v4;
        *(char *)(a1 + v5) = v4;
    }
    return result;
}

