```
def KSA(key):
    S = list(range(256))
    j = 0
    for i in range(256):
        j = (j + S[i] + key[i % len(key)]) % 256
        S[i], S[j] = S[j], S[i]
    return S


def PRGA(S):
    i, j = 0, 0
    while True:
        i = (i + 1) % 256
        j = (j + S[i]) % 256
        S[i], S[j] = S[j], S[i]
        K = S[(S[i] + S[j]) % 256]
        yield K
def RC4Decrypt(key, text):
    S = KSA(key)
    keystream = PRGA(S)
    res = []
    for char in text:
        res.append(char ^ next(keystream))
    return res

key = list(b'SakuraiCora') #放密钥的地方
plaintext = [0xE8,0x2B,0x33,0x25,0xB2,0x55,0xE9,0xD,0x5D,0xAA,0x69,0xFD,0x1B,0x47,0xD1,0x7C,0xA6,0xFF,0x52,0xE1,0x6C,0xE8,0x4C]#解决密文的地方
Rc4encrypt = RC4Decrypt(key, plaintext)
for i in Rc4encrypt:
    print(chr(i), end='')
