    puts("Try to see how lucky you are!!!");
    for ( i = 0; i <= 9; ++i )
    {
        printf("Please enter the %d number:", i + 1);
        printf("\n%d\n",v5 = (rand() % 10));
        scanf("%d", &v4);
        if ( v5 != v4 )
        {
