```
public class MainActivity extends AppCompatActivity {
    SerialPort s1;
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        //初始化串口
        s1 = new SerialPort("/dev/ttySAC2",9600);
        //打开串口
        s1.open();

        //设置监听器接收数据
        s1.setDataReceiveListener(new SerialDataReceiveListener() {
            @Override
            public void onDataReceive(byte[] bytes) {
                //接收数据
                Log.d("GetValues", "onDataReceive: "+Arrays.toString(bytes));
            }
        });
        new Handler().post(new Runnable() {
            @Override
            public void run() {
                if (s1.open())
                    //设置监听器发送数据
                    s1.write(new byte[]{(byte)0xFF,(byte)0xFF});
                else
                    s1.open();
                new Handler().postDelayed(this,1000);
            }
        });
    }
}
```

