## butterfly

分析ida 找到主要逻辑 分析

主要就是处理这个key 我们采用爆破处理这个key 最后输出flag

-   key: 优先 123\\encode.dat.key 的前 8 字节，否则使用常量低 8 字节 b"MMXEncod";
-   逆流程固定为 “(C-K) → ROR1 → swap16 → XOR K”，块数按 ceil(n/8);


![image](blog-assets/p-092adf30b404/187-f30d9d6c9014.png)

解题脚本

```
from __future__ import annotations
import re
from pathlib import Path

# --------- low-level ops ---------

def rotr64_le(b: bytes) -> bytes:
    x = int.from_bytes(b, 'little')
    x = ((x >> 1) | ((x & 1) << 63)) & ((1 << 64) - 1)
    return x.to_bytes(8, 'little')


def rotl64_le(b: bytes) -> bytes:
    x = int.from_bytes(b, 'little')
    x = ((x << 1) | (x >> 63)) & ((1 << 64) - 1)
    return x.to_bytes(8, 'little')


def swap16(b: bytes) -> bytes:
    out = bytearray(8)
    for i in range(0, 8, 2):
        out[i] = b[i + 1]
        out[i + 1] = b[i]
    return bytes(out)

# --------- inverse combos (cover encoder variants) ---------

def inv_combo(c: bytes, k: bytes, rotate: str, swap_first: bool) -> bytes:
    # c = +-k on end. Inverse starts with (c - k) per-byte
    t3 = bytes((c[i] - k[i]) & 0xFF for i in range(8))
    mid = swap16(t3) if swap_first else t3
    rot = rotr64_le(mid) if rotate == 'ror' else rotl64_le(mid)
    post = mid if swap_first else swap16(rot)
    return bytes(post[i] ^ k[i] for i in range(8))


def decode_with_len(
    data: bytes,
    key: bytes,
    len_lo: int,
    len_hi: int,
    rotate: str,
    swap_first: bool,
    process_blocks: str,
    tail_fill: str,
) -> bytes:
    n = len(data)
    buf = bytearray(n + 8)
    buf[:n] = data
    if tail_fill == 'given':
        buf[n] = len_lo & 0xFF
        buf[n + 1] = len_hi & 0xFF
    else:
        buf[n] = 0
        buf[n + 1] = 0

    blocks = (n + 7) // 8 if process_blocks == 'ceil' else (n // 8)
    for bi in range(blocks):
        off = bi * 8
        buf[off:off + 8] = inv_combo(bytes(buf[off:off + 8]), key, rotate, swap_first)
    return bytes(buf[:n])


FLAG_RE_B = re.compile(rb'(?i)(flag\{[^}\r\n]{1,200}\}|ctf\{[^}\r\n]{1,200}\})')


def find_flag_bytes(b: bytes) -> bytes | None:
    m = FLAG_RE_B.search(b)
    if m:
        return m.group(1)
    i = b.lower().find(b'flag{')
    if i == -1:
        i = b.lower().find(b'ctf{')
    if i != -1:
        j = b.find(b'}', i, min(len(b), i + 256))
        if j != -1:
            return b[i:j+1]
    return None


def keys_from_keyfile(p: Path) -> list[bytes]:
    keys: list[bytes] = []
    if p.exists():
        kb = p.read_bytes()
        for off in range(0, max(0, len(kb) - 7)):
            cand = kb[off:off + 8]
            if len(cand) == 8 and cand not in keys:
                keys.append(cand)
    return keys


def build_keys(dir_path: Path) -> list[bytes]:
    keys = keys_from_keyfile(dir_path / 'encode.dat.key')
    const = b'MMXEncode2024' + b'\x00' * (16 - len('MMXEncode2024'))
    for off in range(0, 16 - 7):
        cand = const[off:off + 8]
        if cand not in keys:
            keys.append(cand)
    # prioritize common
    for k in (b'MMXEncod', b'e2024\x00\x00\x00'):
        if k not in keys:
            keys.insert(0, k)
    return keys


def main() -> None:
    d = Path(__file__).resolve().parent
    enc_path = d / 'encode.dat'
    out_flag = d / 'flag.txt'
    data = enc_path.read_bytes()
    keys = build_keys(d)

    rotates = ('ror', 'rol')
    swap_orders = (False, True)
    block_modes = ('ceil', 'floor')
    tails = ('given', 'zeros')

    # quick passes with file length tail
    for key in keys:
        for rotate in rotates:
            for swap_first in swap_orders:
                for process_blocks in block_modes:
                    for tail_fill in tails:
                        dec0 = decode_with_len(
                            data, key, len(data) & 0xFF, (len(data) >> 8) & 0xFF,
                            rotate, swap_first, process_blocks, tail_fill,
                        )
                        fb = find_flag_bytes(dec0)
                        if fb:
                            try:
                                text = fb.decode('utf-8')
                            except Exception:
                                text = fb.decode('latin-1')
                            out_flag.write_text(text, encoding='utf-8')
                            print(text)
                            return

    # full brute for tail 0..65535 across combos
    for key in keys:
        for rotate in rotates:
            for swap_first in swap_orders:
                for process_blocks in block_modes:
                    for v in range(0, 65536):
                        dec = decode_with_len(
                            data, key, v & 0xFF, (v >> 8) & 0xFF,
                            rotate, swap_first, process_blocks, 'given',
                        )
                        fb = find_flag_bytes(dec)
                        if fb:
                            try:
                                text = fb.decode('utf-8')
                            except Exception:
                                text = fb.decode('latin-1')
                            out_flag.write_text(text, encoding='utf-8')
                            print(text)
                            return

    print('NO_FLAG')


if __name__ == '__main__':
    main()
```

